/// AI real-time transcription related interfaces, managing real-time speech-to-text transcription and translation features.
/// <code>AITranscriberStore</code> AI real-time transcription management class for handling speech-to-text transcription and translation business.
/// <code>AITranscriberStore</code> provides a complete set of AI real-time transcription management APIs, including starting, updating, and stopping real-time transcription.
/// Through this class, you can implement real-time speech-to-text transcription with multi-language translation support during audio/video calls or live streaming.
/// <h3>Key Features</h3>
/// <ul>
///   <li>
///     <em>Real-time Transcription</em>：Supports real-time speech-to-text transcription during audio/video sessions
///   </li>
///   <li>
///     <em>Multi-language Source</em>：Supports 20 source languages including Chinese, English, Japanese, Korean, etc.
///   </li>
///   <li>
///     <em>Real-time Translation</em>：Supports translating transcribed text into 15 target languages in real-time
///   </li>
///   <li>
///     <em>State Management</em>：Provides real-time message list state for UI display
///   </li>
/// </ul>
/// <blockquote>
/// Important: Use the <code>create(roomID:)</code> factory method to create an <code>AITranscriberStore</code> instance for a specific room. Configure the source language and translation languages before starting transcription.
///
/// </blockquote>
/// <blockquote>
/// Note: Transcription state updates are delivered through the <code>state</code> publisher. Subscribe to it to receive real-time transcription messages.
///
/// </blockquote>
/// <h3>Usage Example</h3>
/// \code
/// // Create instance for a specific room
/// let store = AITranscriberStore.create(roomID: "your_room_id")
///
/// // Subscribe to state changes
/// store.state.subscribe { state in
///     for message in state.realtimeMessageList {
///         print("Speaker: \(message.speakerUserName)")
///         print("Source text: \(message.sourceText)")
///     }
/// }
///
/// // Configure transcription
/// var config = TranscriberConfig()
/// config.sourceLanguage = .chineseEnglish
/// config.translationLanguages = [.english, .japanese]
///
/// // Start transcription
/// store.startRealtimeTranscriber(config: config) { error in
///     if let error = error {
///         print("Start failed: \(error)")
///     }
/// }
///
/// \endcode<h2>Topics</h2>
/// <h3>Getting Instance</h3>
/// <ul>
///   <li>
///     <code>create(roomID:) - Create an instance for a specific room</code>
///   </li>
/// </ul>
/// <h3>Observing State and Events</h3>
/// <ul>
///   <li>
///     <code>state - Transcriber state data</code>
///   </li>
/// </ul>
/// <h3>Transcription Control</h3>
/// <ul>
///   <li>
///     <code>startTranscription(myLanguage:config:completion:) - Start transcription</code>
///   </li>
///   <li>
///     <code>updateTranscription(myLanguage:config:completion:) - Update transcription configuration</code>
///   </li>
///   <li>
///     <code>stopTranscription(completion:) - Stop transcription</code>
///   </li>
/// </ul>
/// <h3>Interpretation Control</h3>
/// <ul>
///   <li>
///     <code>startInterpretation(myLanguage:config:completion:) - Start interpretation</code>
///   </li>
///   <li>
///     <code>updateInterpretation(myLanguage:config:completion:) - Update interpretation configuration</code>
///   </li>
///   <li>
///     <code>stopInterpretation(completion:) - Stop interpretation</code>
///   </li>
///   <li>
///     <code>setInterpretationVolume(_:completion:) - Set interpretation volume</code>
///   </li>
/// </ul>
/// <h2>See Also</h2>
/// <ul>
///   <li>
///     <code>SourceLanguage</code>
///   </li>
///   <li>
///     <code>TranslationLanguage</code>
///   </li>
///   <li>
///     <code>InterpretationVoice</code>
///   </li>
///   <li>
///     <code>TranscriberMessage</code>
///   </li>
///   <li>
///     <code>TranscriptionConfig</code>
///   </li>
///   <li>
